// Strategy: the previous attempt's single big `assert(P ==> Q) by { if P {
// ... } }` collapsed because z3 had to derive the conclusion
// `det_receive_equal(r1, r2, post1_self_, post2_self_)` from inside a single
// monolithic context where the two ensures' `match`-on-discriminator
// quantifiers never lined up.  Here we case-split *eagerly* with a nested
// `match` on (r1, r2) variant pairs at the top of the proof body.  Each
// branch then carries a small `assert(P_branch ==> det_receive_equal(...))
// by { ... }` whose antecedent `P_branch` is the *variant-specialized*
// instance of the full ensures, so z3 sees a pair of branch-local match
// arms whose triggers already coincide.  Inside each branch we explicitly
// re-expose the relevant `history()`, `my_end_point()`, and `view()`
// equalities.  Every assertion is checked by Verus from the per-branch
// ensures pulled in by the `if`-guard — nothing is taken on faith.

match r1 {
    NetcReceiveResult::Received { sender: s1, message: m1 } => {
        match r2 {
            NetcReceiveResult::Received { sender: s2, message: m2 } => {
                // Both runs took the Received arm.
                assert(r1 is Received);
                assert(r2 is Received);
                assert(r1.view() == NetcReceiveResultView::Received { sender: s1, message: m1@ });
                assert(r2.view() == NetcReceiveResultView::Received { sender: s2, message: m2@ });
                assert(({
                    &&& (post1_self_.my_end_point() == pre_self_.my_end_point())
                    &&& post1_self_.state() is Receiving
                    &&& s1.abstractable()
                    &&& post1_self_.history() == pre_self_.history() + seq![
                        LIoOp::Receive{
                            r: LPacket{
                                dst: post1_self_.my_end_point(),
                                src: s1@,
                                msg: m1@}
                        }]
                    &&& (post2_self_.my_end_point() == pre_self_.my_end_point())
                    &&& post2_self_.state() is Receiving
                    &&& s2.abstractable()
                    &&& post2_self_.history() == pre_self_.history() + seq![
                        LIoOp::Receive{
                            r: LPacket{
                                dst: post2_self_.my_end_point(),
                                src: s2@,
                                msg: m2@}
                        }]
                }) ==> det_receive_equal(r1, r2, post1_self_, post2_self_)) by {
                    if ({
                        &&& (post1_self_.my_end_point() == pre_self_.my_end_point())
                        &&& post1_self_.state() is Receiving
                        &&& s1.abstractable()
                        &&& post1_self_.history() == pre_self_.history() + seq![
                            LIoOp::Receive{
                                r: LPacket{
                                    dst: post1_self_.my_end_point(),
                                    src: s1@,
                                    msg: m1@}
                            }]
                        &&& (post2_self_.my_end_point() == pre_self_.my_end_point())
                        &&& post2_self_.state() is Receiving
                        &&& s2.abstractable()
                        &&& post2_self_.history() == pre_self_.history() + seq![
                            LIoOp::Receive{
                                r: LPacket{
                                    dst: post2_self_.my_end_point(),
                                    src: s2@,
                                    msg: m2@}
                            }]
                    }) {
                        assert(post1_self_.my_end_point() == post2_self_.my_end_point());
                    }
                };
            }
            NetcReceiveResult::TimedOut {} => {
                // Mixed: r1 Received, r2 TimedOut.
                assert(r1 is Received);
                assert(r2 is TimedOut);
                assert(r1.view() == NetcReceiveResultView::Received { sender: s1, message: m1@ });
                assert(r2.view() == NetcReceiveResultView::TimedOut);
            }
            NetcReceiveResult::Error {} => {
                // Mixed: r1 Received, r2 Error.
                assert(r1 is Received);
                assert(r2 is Error);
                assert(r1.view() == NetcReceiveResultView::Received { sender: s1, message: m1@ });
                assert(r2.view() == NetcReceiveResultView::Error);
            }
        }
    }
    NetcReceiveResult::TimedOut {} => {
        match r2 {
            NetcReceiveResult::Received { sender: s2, message: m2 } => {
                // Mixed: r1 TimedOut, r2 Received.
                assert(r1 is TimedOut);
                assert(r2 is Received);
                assert(r1.view() == NetcReceiveResultView::TimedOut);
                assert(r2.view() == NetcReceiveResultView::Received { sender: s2, message: m2@ });
            }
            NetcReceiveResult::TimedOut {} => {
                // Both runs took the TimedOut arm (a unit variant).
                assert(r1 is TimedOut);
                assert(r2 is TimedOut);
                assert(r1.view() == NetcReceiveResultView::TimedOut);
                assert(r2.view() == NetcReceiveResultView::TimedOut);
                assert(r1.view() == r2.view());
                assert(({
                    &&& (post1_self_.my_end_point() == pre_self_.my_end_point())
                    &&& post1_self_.state() is Sending
                    &&& post1_self_.history() == pre_self_.history() + seq![LIoOp::TimeoutReceive{}]
                    &&& (post2_self_.my_end_point() == pre_self_.my_end_point())
                    &&& post2_self_.state() is Sending
                    &&& post2_self_.history() == pre_self_.history() + seq![LIoOp::TimeoutReceive{}]
                }) ==> det_receive_equal(r1, r2, post1_self_, post2_self_)) by {
                    if ({
                        &&& (post1_self_.my_end_point() == pre_self_.my_end_point())
                        &&& post1_self_.state() is Sending
                        &&& post1_self_.history() == pre_self_.history() + seq![LIoOp::TimeoutReceive{}]
                        &&& (post2_self_.my_end_point() == pre_self_.my_end_point())
                        &&& post2_self_.state() is Sending
                        &&& post2_self_.history() == pre_self_.history() + seq![LIoOp::TimeoutReceive{}]
                    }) {
                        assert(post1_self_.my_end_point() == post2_self_.my_end_point());
                        assert(post1_self_.history() == post2_self_.history());
                    }
                };
            }
            NetcReceiveResult::Error {} => {
                // Mixed: r1 TimedOut, r2 Error.
                assert(r1 is TimedOut);
                assert(r2 is Error);
                assert(r1.view() == NetcReceiveResultView::TimedOut);
                assert(r2.view() == NetcReceiveResultView::Error);
            }
        }
    }
    NetcReceiveResult::Error {} => {
        match r2 {
            NetcReceiveResult::Received { sender: s2, message: m2 } => {
                // Mixed: r1 Error, r2 Received.
                assert(r1 is Error);
                assert(r2 is Received);
                assert(r1.view() == NetcReceiveResultView::Error);
                assert(r2.view() == NetcReceiveResultView::Received { sender: s2, message: m2@ });
            }
            NetcReceiveResult::TimedOut {} => {
                // Mixed: r1 Error, r2 TimedOut.
                assert(r1 is Error);
                assert(r2 is TimedOut);
                assert(r1.view() == NetcReceiveResultView::Error);
                assert(r2.view() == NetcReceiveResultView::TimedOut);
            }
            NetcReceiveResult::Error {} => {
                // Both runs took the Error arm (a unit variant).
                assert(r1 is Error);
                assert(r2 is Error);
                assert(r1.view() == NetcReceiveResultView::Error);
                assert(r2.view() == NetcReceiveResultView::Error);
                assert(r1.view() == r2.view());
                assert(({
                    &&& (post1_self_.my_end_point() == pre_self_.my_end_point())
                    &&& post1_self_.state() is Error
                    &&& (post2_self_.my_end_point() == pre_self_.my_end_point())
                    &&& post2_self_.state() is Error
                }) ==> det_receive_equal(r1, r2, post1_self_, post2_self_)) by {
                    if ({
                        &&& (post1_self_.my_end_point() == pre_self_.my_end_point())
                        &&& post1_self_.state() is Error
                        &&& (post2_self_.my_end_point() == pre_self_.my_end_point())
                        &&& post2_self_.state() is Error
                    }) {
                        assert(post1_self_.my_end_point() == post2_self_.my_end_point());
                    }
                };
            }
        }
    }
}
